import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Google Drive Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/google-drive.md","filePath":"my/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"my/upload/google-drive.md"};function c(p,e,h,g,u,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="google-drive-channel-ထည့်သွင်းခြင်း" tabindex="-1">Google Drive Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#google-drive-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Google Drive Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>ဘာကြောင့်လိုလဲ</th></tr></thead><tbody><tr><td>Google account</td><td>Google Cloud ကို access လုပ်ရန်နှင့် Google Drive ကို authorize လုပ်ရန်</td></tr><tr><td>Google Cloud project</td><td>Drive API enable လုပ်ရန်နှင့် OAuth credentials ဖန်တီးရန်</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed က <code>Client ID</code>, <code>Client Secret</code>, <code>Refresh Token</code> ရယူရန်</td></tr><tr><td>သင့် ImgBed domain</td><td>OAuth redirect URI အတွက်။ သင်တကယ်သုံးတဲ့ domain နဲ့ match ဖြစ်ရပါမယ်။</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-google-drive-api-enable-လုပ်ပါ" tabindex="-1">Step 1: Google Drive API Enable လုပ်ပါ <a class="header-anchor" href="#step-1-google-drive-api-enable-လုပ်ပါ" aria-label="Permalink to &quot;Step 1: Google Drive API Enable လုပ်ပါ&quot;">​</a></h3><ol><li>Google Cloud Console ကိုဖွင့်ပါ။</li><li>project အသစ်ဖန်တီးပါ သို့မဟုတ် existing project ကိုရွေးပါ။</li><li><code>APIs &amp; Services</code> ကိုသွားပါ။</li><li><code>Enable APIs and Services</code> ကိုနှိပ်ပါ။</li><li><code>Google Drive API</code> ကိုရှာပါ။</li><li>ဖွင့်ပြီး enable ကိုနှိပ်ပါ။</li></ol><h3 id="step-2-oauth-consent-screen-configure-လုပ်ပါ" tabindex="-1">Step 2: OAuth Consent Screen Configure လုပ်ပါ <a class="header-anchor" href="#step-2-oauth-consent-screen-configure-လုပ်ပါ" aria-label="Permalink to &quot;Step 2: OAuth Consent Screen Configure လုပ်ပါ&quot;">​</a></h3><ol><li>Google Cloud မှာ <code>Google Auth Platform</code> ကိုဖွင့်ပါ။</li><li>app name, support email, developer contact email စတဲ့ basic <code>Branding</code> information ကိုဖြည့်ပါ။</li><li><code>Audience</code> ကိုဖွင့်ပါ။</li><li>self-hosted personal deployments အများစုအတွက် <code>External</code> ကိုရွေးပါ။</li><li><code>External</code> ရွေးလျှင် authorize လုပ်မယ့် Google account ကို <code>Test users</code> ထဲထည့်ပါ။</li><li><code>Data Access</code> ကိုဖွင့်ပါ။</li><li>လိုအပ်တဲ့ Google Drive permissions တွေထည့်ပါ။</li></ol><h3 id="step-3-oauth-2-0-client-ဖန်တီးပါ" tabindex="-1">Step 3: OAuth 2.0 Client ဖန်တီးပါ <a class="header-anchor" href="#step-3-oauth-2-0-client-ဖန်တီးပါ" aria-label="Permalink to &quot;Step 3: OAuth 2.0 Client ဖန်တီးပါ&quot;">​</a></h3><ol><li><code>Google Auth Platform</code> ထဲက <code>Clients</code> ကိုဖွင့်ပါ။</li><li>client အသစ်ဖန်တီးပါ။</li><li>application type ကို <code>Web application</code> ထားပါ။</li><li>မှတ်မိလွယ်တဲ့ client name ထည့်ပါ။</li><li>authorized JavaScript origins မှာ သင့် ImgBed URL ထည့်ပါ၊ ဥပမာ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>authorized redirect URIs မှာ ထည့်ပါ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>client ဖန်တီးပြီးနောက် ဒီ values တွေ copy လုပ်ပါ:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-imgbed-မှာ-google-drive-channel-ဖြည့်ပါ" tabindex="-1">Step 4: ImgBed မှာ Google Drive Channel ဖြည့်ပါ <a class="header-anchor" href="#step-4-imgbed-မှာ-google-drive-channel-ဖြည့်ပါ" aria-label="Permalink to &quot;Step 4: ImgBed မှာ Google Drive Channel ဖြည့်ပါ&quot;">​</a></h2><p>Upload Settings မှာ <code>Google Drive</code> ရွေးပြီး:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>မှတ်မိလွယ်တဲ့အမည်၊ ဥပမာ <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Google Cloud မှ Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud မှ Client Secret</td></tr><tr><td>Refresh Token</td><td>အခုခဏဗလာထားပါ။ နောက် step မှာရယူပါ။</td></tr><tr><td>Root directory</td><td>Optional။ default က <code>imgbed</code>။</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-refresh-token-ရယူပါ" tabindex="-1">Step 5: Refresh Token ရယူပါ <a class="header-anchor" href="#step-5-refresh-token-ရယူပါ" aria-label="Permalink to &quot;Step 5: Refresh Token ရယူပါ&quot;">​</a></h2><ol><li><code>Get Token</code> ကိုနှိပ်ပါ။</li><li>connect လုပ်ချင်တဲ့ Google account ကိုရွေးပါ။</li><li>authorization prompts တွေကိုပြီးအောင်လုပ်ပါ။</li><li>callback page မှာ <code>Refresh Token</code> ပြပါမယ်။</li><li>အဲဒါကို copy လုပ်ပါ။</li><li>ImgBed ကိုပြန်သွားပြီး <code>Refresh Token</code> field ထဲ paste လုပ်ပါ။</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>နောက်ပိုင်း Google account ပြောင်းလျှင်၊ OAuth client ပြောင်းလျှင်၊ သို့မဟုတ် authorization ဟောင်း expire ဖြစ်လျှင် channel ကို delete လုပ်စရာမလိုပါ။ edit page ကိုဖွင့်ပြီး <code>Reauthorize</code> ကိုနှိပ်ပါ။</p><h2 id="step-6-channel-save-လုပ်ပါ" tabindex="-1">Step 6: Channel Save လုပ်ပါ <a class="header-anchor" href="#step-6-channel-save-လုပ်ပါ" aria-label="Permalink to &quot;Step 6: Channel Save လုပ်ပါ&quot;">​</a></h2><p>fields အားလုံးဖြည့်ပြီးနောက် channel ကို save လုပ်ပါ။</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; project ဖန်တီး သို့မဟုတ် ရွေးပါ</span></span>
<span class="line"><span>-&gt; Google Drive API enable လုပ်ပါ</span></span>
<span class="line"><span>-&gt; Google Auth Platform configure လုပ်ပါ</span></span>
<span class="line"><span>-&gt; Audience က External ဖြစ်လျှင် သင့် Google account ကို Test users ထဲထည့်ပါ</span></span>
<span class="line"><span>-&gt; Web application OAuth client ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; redirect URI အဖြစ် https://your-domain.com/api/oauth/google/callback သုံးပါ</span></span>
<span class="line"><span>-&gt; Client ID နဲ့ Client Secret ကို ImgBed ထဲထည့်ပါ</span></span>
<span class="line"><span>-&gt; Get Token ကိုနှိပ်ပါ</span></span>
<span class="line"><span>-&gt; Google နဲ့ sign in ဝင်ပြီး authorize လုပ်ပါ</span></span>
<span class="line"><span>-&gt; callback page မှ Refresh Token copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed မှာ paste လုပ်ပြီး save လုပ်ပါ</span></span>
<span class="line"><span>-&gt; test image upload လုပ်ပါ</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,31)])])}const k=i(d,[["render",c]]);export{f as __pageData,k as default};
